    "depression",
    "sad",
    "hopeless",
    "overwhelmed",
    "mental",
    "panic",
    "cry",
    "crying",
    "worthless",
    "suicide",
    "self harm",
  ],
  academic_stress: [
    "grades",
    "exam",
    "test",
    "homework",
    "school",
    "failing",
    "college",
    "gpa",
    "teacher",
    "class",
    "study",
    "stressed",
