function renderContact(contact) {
  const raw = String(contact || "");
  const trimmed = raw.trim();
  if (!trimmed) return null;

  const isHttpUrl = /^https?:\/\//i.test(trimmed);
  const isWwwUrl = /^www\./i.test(trimmed);
  if (isHttpUrl || isWwwUrl) {
    const href = isWwwUrl ? "https://" + trimmed : trimmed;
    return (
      <a
        className="resource-contact-link"
        href={href}
        target="_blank"
        rel="noopener noreferrer"
      >
        {raw}
      </a>
    );
  }

  // Phone numbers (e.g. "1-800-422-4453") should become tel: links.
  const digitsOnly = trimmed.replace(/\D/g, "");
  if (digitsOnly.length >= 10) {
    const telHref = "tel:" + trimmed.replace(/[^\d+]/g, "");
    return (
      <a className="resource-contact-link" href={telHref}>
        {raw}
      </a>
    );
  }

  // Short codes in phrases like "Text HOME to 741741" or "Call or text 988".
  const numberMatches = trimmed.match(/\d+/g);
  const lastNumber = numberMatches?.[numberMatches.length - 1];
  if (lastNumber && lastNumber.length <= 6 && digitsOnly.length <= 6) {
    const start = trimmed.lastIndexOf(lastNumber);
    const before = trimmed.slice(0, start);
    const after = trimmed.slice(start + lastNumber.length);
    return (
      <>
        {before}
        <a className="resource-contact-link" href={`sms:${lastNumber}`}>
          {lastNumber}
        </a>
        {after}
      </>
    );
  }

  // Website domains without protocol (e.g. "khanacademy.org").
  if (!/\s/.test(trimmed) && /\./.test(trimmed)) {
    const domainLike = /^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/.test(trimmed);
    if (domainLike) {
      return (
        <a
          className="resource-contact-link"
          href={"https://" + trimmed}
          target="_blank"
          rel="noopener noreferrer"
        >
          {raw}
        </a>
      );
    }
  }

  return raw;
}

function getResponse(input) {
  const lower = input.toLowerCase();

  let matchedCategory = "general";
  for (const [category, keywords] of Object.entries(categories)) {
    if (
      keywords.some((keyword) =>
        lower.includes(keyword.toLowerCase())
      )
    ) {
      matchedCategory = category;
      break;
    }
  }

  return {
    message: messages[matchedCategory],
    category: matchedCategory,
    resources: resourcesByCategory[matchedCategory],
  };
}

const systemPrompt = `
You are ClearPath, a supportive guide for high school students.
When a student shares what they're struggling with, respond with ONLY a valid JSON object in this exact format, no preamble, no markdown:

{
  "message": "A warm, empathetic 3-4 sentence response that validates their feelings without being dramatic or clinical.",
  "resources": [
    {
      "name": "Resource Name",
      "description": "One sentence about what this is.",
      "contact": "phone number or website",
      "type": "national"
    }
  ]
}

Rules:
- Include exactly 2 resources where type is "national" that are most relevant.
- Include 1 to 2 resources where type is "school" that are most relevant.
- Do NOT always include the same school resources; choose what fits the student's situation.
- Available national resources (use these exact names/contacts):
  - Crisis Text Line — Text HOME to 741741
  - 988 Suicide & Crisis Lifeline — Call or text 988
  - StopBullying.gov — stopbullying.gov
  - Khan Academy — khanacademy.org
  - Feeding America — feedingamerica.org
  - 211 Helpline — Call or text 211
  - Childhelp National Child Abuse Hotline — 1-800-422-4453
  - Teen Line — Text TEEN to 839863
  - GriefShare — griefshare.org
- Available school resources (use these exact names/contacts):
  - School Counselor — Visit your front office
  - School Social Worker — Ask at the front office
  - Peer Tutoring Program — Ask your teacher or counselor
  - School Lunch Program — Ask your school's front office
  - School Clubs & Activities — Ask your counselor or front office
  - School Administration — Visit your front office

Keep everything concise and actionable. Output ONLY the JSON object.
`.trim();

function App() {
  const [input, setInput] = useState("");
  const [response, setResponse] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakStatus, setSpeakStatus] = useState("idle");
  const [error, setError] = useState("");
  const [toast, setToast] = useState("");
  const [inputShake, setInputShake] = useState(false);

  const groqKey = process.env.REACT_APP_GROQ_KEY;
  const elevenVoiceId = process.env.REACT_APP_ELEVENLABS_VOICE_ID;

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!input.trim()) {
      setError("Tell us what's going on first.");
      setInputShake(true);
      setTimeout(() => setInputShake(false), 400);
      return;
    }

    setIsLoading(true);
    setResponse(null);

    try {
      const groqKeyValue = process.env.REACT_APP_GROQ_KEY;
      if (!groqKeyValue) {
        throw new Error("Missing REACT_APP_GROQ_KEY");
      }

      const groqResponse = await fetch(
        "https://api.groq.com/openai/v1/chat/completions",
        {
          method: "POST",
          headers: {
            Authorization: "Bearer " + groqKeyValue,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            model: "llama-3.3-70b-versatile",
            messages: [
              { role: "system", content: systemPrompt },
              { role: "user", content: input },
            ],
            temperature: 0.7,
            max_tokens: 800,
          }),
        }
      );

      if (!groqResponse.ok) {
        // Helps diagnose 400s (bad request, auth issues, etc.)
        const errText = await groqResponse.text().catch(() => "");
        console.error("Groq error response", {
          status: groqResponse.status,
          body: errText,
        });
        throw new Error(
          `Groq request failed: ${errText || groqResponse.status}`
        );
      }

      const data = await groqResponse.json();
      const content = data?.choices?.[0]?.message?.content;

      let parsed;
      try {
        parsed = JSON.parse(content);
      } catch {
        throw new Error("Invalid JSON from model");
      }

      if (
        !parsed ||
        typeof parsed.message !== "string" ||
        !Array.isArray(parsed.resources)
      ) {
        throw new Error("Malformed JSON from model");
      }

      setResponse({
        message: parsed.message,
        resources: parsed.resources,
      });
    } catch {
      const fallback = getResponse(input);
      setResponse({
        message: fallback.message,
        resources: fallback.resources,
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleReadAloud = async () => {
    if (!response?.message || !elevenVoiceId) {
      setToast("Voice unavailable — try again");
      setTimeout(() => setToast(""), 3000);
      return;
    }

    try {
      setIsSpeaking(true);
      setSpeakStatus("loading");

      const res = await fetch(
        `/api/elevenlabs/text-to-speech/${elevenVoiceId}`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: response.message,
            model_id: "eleven_monolingual_v1",
            voice_settings: {
              stability: 0.75,
              similarity_boost: 0.75,
            },
          }),
        }
      );

      if (!res.ok) {
        throw new Error("ElevenLabs request failed");
      }

      const blob = await res.blob();
      const url = URL.createObjectURL(blob);

      setSpeakStatus("playing");
      const audio = new Audio(url);
      audio.onended = () => {
        setSpeakStatus("idle");
        setIsSpeaking(false);
        URL.revokeObjectURL(url);
      };
      audio.onerror = () => {
        setSpeakStatus("idle");
        setIsSpeaking(false);
        URL.revokeObjectURL(url);
        setToast("Voice unavailable — try again");
        setTimeout(() => setToast(""), 3000);
      };
      await audio.play();
    } catch {
      setSpeakStatus("idle");
      setIsSpeaking(false);
      setToast("Voice unavailable — try again");
      setTimeout(() => setToast(""), 3000);
    }
  };

  const renderSpeakLabel = () => {
    if (speakStatus === "loading") return "Loading...";
    if (speakStatus === "playing") return "Playing";
    return "Read Aloud";
  };

  return (
    <div className="app">
      <div className="app-shell">
        <header className="app-header">
          <div className="app-title">ClearPath</div>
          <p className="app-tagline">Find your way to support.</p>
        </header>

        <main>
          <section className="input-section">
            <form onSubmit={handleSubmit}>
              <label htmlFor="story" className="input-label">
                What's going on? You can be honest here.
              </label>
              <textarea
                id="story"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                className={`input-textarea ${
                  inputShake ? "input-textarea--shake" : ""
                }`}
                placeholder="What's going on? You can be honest here."
                rows={6}
              />
              {error && <div className="input-error">{error}</div>}
              <button
                type="submit"
                className={`primary-button ${
                  isLoading ? "primary-button--loading" : ""
                }`}
                disabled={isLoading}
              >
                {isLoading ? (
                  <span className="button-loading">
                    <span className="button-spinner" />
                    Finding support...
                  </span>
                ) : (
                  "Find Support"
                )}
              </button>
            </form>
          </section>

          {response && (
            <section className="response-section">
              <div className="response-card">
                <p className="response-message">{response.message}</p>
                <div className="response-actions">
                  <button
                    type="button"
                    className={`secondary-button ${
                      isSpeaking ? "secondary-button--loading" : ""
                    }`}
                    onClick={handleReadAloud}
                    disabled={isSpeaking}
                  >
                    {isSpeaking && (
                      <span className="button-spinner button-spinner--small" />
                    )}
                    {renderSpeakLabel()}
                  </button>
                </div>
              </div>

              <div className="resources-grid">
                {response.resources.map((resource, index) => (
                  <article
                    key={`${resource.name}-${index}`}
                    className="resource-card"
                    style={{
                      animationDelay: `${index * 80}ms`,
                    }}
                  >
                    <div className="resource-card-header">
                      <h3 className="resource-name">{resource.name}</h3>
                      <span
                        className={`resource-badge resource-badge--${
                          resource.type === "school" ? "school" : "national"
                        }`}
                      >
                        {resource.type === "school" ? "School" : "National"}
                      </span>
                    </div>
                    <p className="resource-description">
                      {resource.description}
                    </p>
                    <p className="resource-contact">{resource.contact}</p>
                  </article>
                ))}
              </div>
            </section>
          )}
        </main>

        {toast && <div className="toast">{toast}</div>}
      </div>
    </div>
  );
}

